/**
 * Echo Form Component
 * Форма для ввода результатов ЭхоКГ
 * Согласно MASTER_TODO_LIST строка 248
 */
import { useState, useEffect } from 'react';
import {

  Card,
  CardContent,
  Typography,
  Button,
  Alert,

  Input,
  Textarea } from
'../ui/macos';
import {
  Heart,

  Save,
  ChevronDown,
  ChevronRight,

  Sparkles,
  AlertTriangle,
  CheckCircle } from
'lucide-react';
import { api } from '../../api/client';

import logger from '../../utils/logger';
const EchoForm = ({ patientId, visitId, onSave, initialData = null }) => {
  const [echoData, setEchoData] = useState({
    // Левый желудочек
    leftVentricle: {
      edd: '', // КДР
      esd: '', // КСР
      ef: '', // ФВ
      fs: '', // ФС
      ivs: '', // МЖП
      pw: '' // ЗС
    },
    // Правый желудочек
    rightVentricle: {
      rvdd: '', // КДР ПЖ
      rvot: '' // ВТ ПЖ
    },
    // Предсердия
    atria: {
      la: '', // ЛП
      ra: '' // ПП
    },
    // Клапаны
    valves: {
      mitral: {
        e: '',
        a: '',
        e_a: '',
        decel_time: ''
      },
      tricuspid: {
        e: '',
        a: '',
        e_a: ''
      },
      aortic: {
        peak_velocity: '',
        mean_gradient: '',
        ava: ''
      },
      pulmonary: {
        peak_velocity: '',
        mean_gradient: ''
      }
    },
    // Дополнительные параметры
    additional: {
      pericardium: '',
      aorta: '',
      comments: ''
    },
    // Заключение
    conclusion: ''
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [expandedSections, setExpandedSections] = useState({
    leftVentricle: true,
    rightVentricle: false,
    atria: false,
    valves: false,
    additional: false
  });

  useEffect(() => {
    if (initialData) {
      setEchoData(initialData);
    }
  }, [initialData]);

  const handleChange = (section, field, value) => {
    setEchoData((prev) => ({
      ...prev,
      [section]: {
        ...prev[section],
        [field]: value
      }
    }));
  };

  const toggleSection = (section) => {
    setExpandedSections((prev) => ({
      ...prev,
      [section]: !prev[section]
    }));
  };

  const handleSave = async () => {
    try {
      setLoading(true);
      setError('');

      const response = await api.post('/cardiology/echo-results', {
        patient_id: patientId,
        visit_id: visitId,
        echo_data: echoData
      });

      if (response.status === 200) {
        setSuccess('Результаты ЭхоКГ сохранены успешно');
        if (onSave) {
          onSave(response.data);
        }
      }
    } catch (err) {
      setError('Ошибка при сохранении результатов ЭхоКГ');
      logger.error('Echo form save error:', err);
    } finally {
      setLoading(false);
    }
  };

  const renderSection = (title, section, fields, expanded) =>
  <div style={{ marginBottom: 24 }}>
      <div
      role="button"
      tabIndex={0}
      style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        padding: '12px 16px',
        backgroundColor: 'var(--mac-bg-secondary)',
        border: '1px solid var(--mac-border)',
        borderRadius: '8px',
        cursor: 'pointer'
      }}
      onClick={() => toggleSection(section)}
      onKeyDown={(event) => {
        if (event.key === 'Enter' || event.key === ' ') {
          event.preventDefault();
          toggleSection(section);
        }
      }}>
      
        <Typography variant="subtitle1" style={{ fontWeight: 500 }}>
          {title}
        </Typography>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          {expanded ? <ChevronDown style={{ width: 16, height: 16 }} /> : <ChevronRight style={{ width: 16, height: 16 }} />}
        </div>
      </div>
      
      {expanded &&
    <div style={{ padding: 16, marginTop: 8, border: '1px solid var(--mac-border)', borderRadius: 8 }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: 16 }}>
            {fields.map((field) =>
        <div key={field.key}>
                <Input
            label={field.label}
            value={echoData[section][field.key]}
            onChange={(e) => handleChange(section, field.key, e.target.value)}
            placeholder={field.placeholder} />
          
              </div>
        )}
          </div>
        </div>
    }
    </div>;


  return (
    <Card>
      <CardContent>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
          <Typography variant="h6">
            <Heart style={{ marginRight: 8, verticalAlign: 'middle' }} />
            Результаты ЭхоКГ
          </Typography>
          
          <div style={{ display: 'flex', gap: 8 }}>
            <Button
              variant="outline"
              onClick={() => {/* AI анализ */}}>
              
              <Sparkles style={{ width: 16, height: 16, marginRight: 8 }} />
              AI Анализ
            </Button>
            <Button
              variant="primary"
              onClick={handleSave}
              disabled={loading}>
              
              <Save style={{ width: 16, height: 16, marginRight: 8 }} />
              Сохранить
            </Button>
          </div>
        </div>

        {error &&
        <Alert severity="error" style={{ marginBottom: 16 }}>
            <AlertTriangle style={{ width: 16, height: 16, marginRight: 8 }} />
            {error}
          </Alert>
        }

        {success &&
        <Alert severity="success" style={{ marginBottom: 16 }}>
            <CheckCircle style={{ width: 16, height: 16, marginRight: 8 }} />
            {success}
          </Alert>
        }

        {/* Левый желудочек */}
        {renderSection(
          'Левый желудочек',
          'leftVentricle',
          [
          { key: 'edd', label: 'КДР', placeholder: 'Норма: 35-55 мм' },
          { key: 'esd', label: 'КСР', placeholder: 'Норма: 20-35 мм' },
          { key: 'ef', label: 'ФВ', placeholder: 'Норма: 55-75%' },
          { key: 'fs', label: 'ФС', placeholder: 'Норма: 28-45%' },
          { key: 'ivs', label: 'МЖП', placeholder: 'Норма: 6-11 мм' },
          { key: 'pw', label: 'ЗС', placeholder: 'Норма: 6-11 мм' }],

          expandedSections.leftVentricle
        )}

        {/* Правый желудочек */}
        {renderSection(
          'Правый желудочек',
          'rightVentricle',
          [
          { key: 'rvdd', label: 'КДР ПЖ', placeholder: 'Норма: 19-28 мм' },
          { key: 'rvot', label: 'ВТ ПЖ', placeholder: 'Норма: 19-28 мм' }],

          expandedSections.rightVentricle
        )}

        {/* Предсердия */}
        {renderSection(
          'Предсердия',
          'atria',
          [
          { key: 'la', label: 'ЛП', placeholder: 'Норма: 19-40 мм' },
          { key: 'ra', label: 'ПП', placeholder: 'Норма: 19-40 мм' }],

          expandedSections.atria
        )}

        {/* Клапаны */}
        {renderSection(
          'Клапаны',
          'valves',
          [
          { key: 'mitral.e', label: 'Митральный клапан E', placeholder: 'Норма: 0.6-1.3 м/с' },
          { key: 'mitral.a', label: 'Митральный клапан A', placeholder: 'Норма: 0.4-0.8 м/с' },
          { key: 'aortic.peak_velocity', label: 'Аортальный клапан', placeholder: 'Норма: 1.0-1.7 м/с' },
          { key: 'tricuspid.e', label: 'Трехстворчатый клапан E', placeholder: 'Норма: 0.3-0.7 м/с' }],

          expandedSections.valves
        )}

        {/* Дополнительные параметры */}
        {renderSection(
          'Дополнительные параметры',
          'additional',
          [
          { key: 'pericardium', label: 'Перикард', placeholder: 'Описание состояния перикарда' },
          { key: 'aorta', label: 'Аорта', placeholder: 'Описание состояния аорты' }],

          expandedSections.additional
        )}

        {/* Комментарии */}
        <div style={{ marginTop: 24 }}>
          <Typography variant="subtitle1" style={{ marginBottom: 8 }}>
            Комментарии
          </Typography>
          <Textarea
            value={echoData.additional.comments}
            onChange={(e) => handleChange('additional', 'comments', e.target.value)}
            placeholder="Дополнительные замечания и наблюдения..."
            rows={4} />
          
        </div>

        {/* Заключение */}
        <div style={{ marginTop: 24 }}>
          <Typography variant="subtitle1" style={{ marginBottom: 8 }}>
            Заключение
          </Typography>
          <Textarea
            value={echoData.conclusion}
            onChange={(e) => setEchoData((prev) => ({ ...prev, conclusion: e.target.value }))}
            placeholder="Заключение по результатам ЭхоКГ..."
            rows={6} />
          
        </div>
      </CardContent>
    </Card>);

};

export default EchoForm;

// Система модальных окон
import { createContext, useContext, useState, useCallback, useEffect } from 'react';
import { useTheme } from '../../contexts/ThemeContext';

// Контекст для модальных окон
const ModalContext = createContext();
let openModalExternal = null;

const getFontSize = (size) => {
  const sizes = {
    sm: '0.875rem',
    md: '1rem',
    lg: '1.125rem',
    xl: '1.25rem'
  };
  return sizes[size] || sizes.md;
};

/**
 * Провайдер контекста модальных окон
 */
export function ModalProvider({ children }) {
  const [modals, setModals] = useState([]);
  const theme = useTheme();

  const openModal = useCallback((modal) => {
    const id = Date.now() + Math.random();
    const newModal = {
      id,
      type: 'default',
      size: 'medium',
      closable: true,
      ...modal
    };

    setModals((prev) => [...prev, newModal]);
    return id;
  }, []);

  const closeModal = useCallback((id) => {
    setModals((prev) => prev.filter((modal) => modal.id !== id));
  }, []);

  const closeAllModals = useCallback(() => {
    setModals([]);
  }, []);

  useEffect(() => {
    openModalExternal = openModal;
    return () => {
      if (openModalExternal === openModal) {
        openModalExternal = null;
      }
    };
  }, [openModal]);

  const value = {
    modals,
    openModal,
    closeModal,
    closeAllModals
  };

  return (
    <ModalContext.Provider value={value}>
      {children}
      <ModalContainer modals={modals} onClose={closeModal} theme={theme} />
    </ModalContext.Provider>);

}

/**
 * Хук для использования модальных окон
 */
export function useModal() {
  const context = useContext(ModalContext);
  if (!context) {
    throw new Error('useModal must be used within a ModalProvider');
  }
  return context;
}

/**
 * Контейнер для отображения модальных окон
 */
function ModalContainer({ modals, onClose, theme }) {

  const overlayStyle = {
    position: 'fixed',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    backgroundColor: 'rgba(0, 0, 0, 0.5)',
    zIndex: 1000,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    padding: '1rem'
  };

  return (
    <>
      {modals.map((modal) =>
      <div key={modal.id} style={overlayStyle}>
          <ModalItem
          modal={modal}
          onClose={onClose}
          theme={theme} />

        </div>
      )}
    </>);

}

/**
 * Отдельное модальное окно
 */
function ModalItem({ modal, onClose }) {
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    // Анимация появления
    const timer = setTimeout(() => setIsVisible(true), 10);
    return () => clearTimeout(timer);
  }, []);

  const getSize = (size) => {
    const sizes = {
      small: '400px',
      medium: '600px',
      large: '800px',
      xlarge: '1000px',
      fullscreen: '95vw'
    };
    return sizes[size] || sizes.medium;
  };

  const modalStyle = {
    backgroundColor: 'var(--color-background-primary)',
    borderRadius: '12px',
    boxShadow: '0 20px 40px rgba(0, 0, 0, 0.3)',
    maxWidth: getSize(modal.size),
    width: '100%',
    maxHeight: '90vh',
    overflow: 'hidden',
    transform: isVisible ? 'scale(1)' : 'scale(0.9)',
    opacity: isVisible ? 1 : 0,
    transition: 'all 0.3s ease',
    display: 'flex',
    flexDirection: 'column'
  };

  const headerStyle = {
    padding: '1.5rem',
    borderBottom: '1px solid var(--color-border-medium)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between'
  };

  const titleStyle = {
    fontSize: getFontSize('xl'),
    fontWeight: '600',
    color: 'var(--color-text-primary)',
    margin: 0
  };

  const closeButtonStyle = {
    background: 'none',
    border: 'none',
    fontSize: getFontSize('xl'),
    cursor: 'pointer',
    color: 'var(--color-text-secondary)',
    padding: '0.5rem',
    borderRadius: '4px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    width: '32px',
    height: '32px'
  };

  const contentStyle = {
    padding: '1.5rem',
    flex: 1,
    overflow: 'auto'
  };

  const footerStyle = {
    padding: '1.5rem',
    borderTop: '1px solid var(--color-border-medium)',
    display: 'flex',
    justifyContent: 'flex-end',
    gap: '0.5rem'
  };

  const handleOverlayClick = (e) => {
    if (e.target === e.currentTarget && modal.closable) {
      onClose(modal.id);
    }
  };

  const handleKeyDown = useCallback((e) => {
    if (e.key === 'Escape' && modal.closable) {
      onClose(modal.id);
    }
  }, [modal.closable, modal.id, onClose]);

  useEffect(() => {
    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);

  return (
    <div
      style={modalStyle}
      onMouseDown={handleOverlayClick}>

      {modal.title &&
      <div style={headerStyle}>
          <h2 style={titleStyle}>{modal.title}</h2>
          {modal.closable &&
        <button
          style={closeButtonStyle}
          onClick={() => onClose(modal.id)}
          onMouseOver={(e) => {
            e.target.style.backgroundColor = 'var(--color-background-tertiary)';
          }}
          onMouseOut={(e) => {
            e.target.style.backgroundColor = 'transparent';
          }}>

              ×
            </button>
        }
        </div>
      }

      <div style={contentStyle}>
        {modal.content}
      </div>

      {modal.footer &&
      <div style={footerStyle}>
          {modal.footer}
        </div>
      }
    </div>);

}

/**
 * Базовый компонент модального окна
 */
export function Modal({
  isOpen,
  onClose,
  title,
  children,
  footer,
  size = 'medium',
  closable = true,
  ...props
}) {void
  useTheme();

  const getSize = (size) => {
    const sizes = {
      small: '400px',
      medium: '600px',
      large: '800px',
      xlarge: '1000px',
      fullscreen: '95vw'
    };
    return sizes[size] || sizes.medium;
  };

  const overlayStyle = {
    position: 'fixed',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    backgroundColor: 'rgba(0, 0, 0, 0.5)',
    zIndex: 1000,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    padding: '1rem'
  };

  const modalStyle = {
    backgroundColor: 'var(--color-background-primary)',
    borderRadius: '12px',
    boxShadow: '0 20px 40px rgba(0, 0, 0, 0.3)',
    maxWidth: getSize(size),
    width: '100%',
    maxHeight: '90vh',
    overflow: 'hidden',
    display: 'flex',
    flexDirection: 'column',
    ...props.style
  };

  const headerStyle = {
    padding: '1.5rem',
    borderBottom: '1px solid var(--color-border-medium)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between'
  };

  const titleStyle = {
    fontSize: getFontSize('xl'),
    fontWeight: '600',
    color: 'var(--color-text-primary)',
    margin: 0
  };

  const closeButtonStyle = {
    background: 'none',
    border: 'none',
    fontSize: getFontSize('xl'),
    cursor: 'pointer',
    color: 'var(--color-text-secondary)',
    padding: '0.5rem',
    borderRadius: '4px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    width: '32px',
    height: '32px'
  };

  const contentStyle = {
    padding: '1.5rem',
    flex: 1,
    overflow: 'auto'
  };

  const footerStyle = {
    padding: '1.5rem',
    borderTop: '1px solid var(--color-border-medium)',
    display: 'flex',
    justifyContent: 'flex-end',
    gap: '0.5rem'
  };

  const handleOverlayClick = (e) => {
    if (e.target === e.currentTarget && closable) {
      onClose();
    }
  };

  const handleKeyDown = useCallback((e) => {
    if (e.key === 'Escape' && closable) {
      onClose();
    }
  }, [closable, onClose]);

  useEffect(() => {
    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);

  if (!isOpen) return null;

  return (
    <div
      style={overlayStyle}
      onMouseDown={handleOverlayClick}>

      <div style={modalStyle}>
        {title &&
        <div style={headerStyle}>
            <h2 style={titleStyle}>{title}</h2>
            {closable &&
          <button
            style={closeButtonStyle}
            onClick={onClose}
            onMouseOver={(e) => {
              e.target.style.backgroundColor = 'var(--color-background-tertiary)';
            }}
            onMouseOut={(e) => {
              e.target.style.backgroundColor = 'transparent';
            }}>

                ×
              </button>
          }
          </div>
        }

        <div style={contentStyle}>
          {children}
        </div>

        {footer &&
        <div style={footerStyle}>
            {footer}
          </div>
        }
      </div>
    </div>);

}

/**
 * Утилиты для быстрого создания модальных окон
 */
export const modal = {
  confirm: (message, onConfirm, onCancel) => {
    if (!openModalExternal) {
      return null;
    }
    return openModalExternal({
      title: 'Подтверждение',
      content: <p>{message}</p>,
      footer:
      <div style={{ display: 'flex', gap: '8px' }}>
          <button onClick={onCancel}>Отмена</button>
          <button onClick={onConfirm}>Подтвердить</button>
        </div>

    });
  },

  alert: (message, onClose) => {
    if (!openModalExternal) {
      return null;
    }
    return openModalExternal({
      title: 'Уведомление',
      content: <p>{message}</p>,
      footer:
      <button onClick={onClose}>OK</button>

    });
  }
};

/**
 * Photo Uploader Component
 * Загрузка фото до/после с поддержкой HEIC
 * Согласно MASTER_TODO_LIST строка 265
 */
import { useState, useCallback, useRef } from 'react';
import {
  Box,
  Card,
  CardContent,
  Typography,
  Button,
  Alert,
  Progress,
  Input,
  Select,
  Option,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions } from
'../ui/macos';
import {
  Camera,
  Upload,
  Trash2,

  ArrowLeftRight,


  CameraIcon } from



'lucide-react';
import { useDropzone } from 'react-dropzone';
import heic2any from 'heic2any';
import { api } from '../../api/client';

import logger from '../../utils/logger';
const PhotoUploader = ({ visitId, onDataUpdate }) => {
  const [photos, setPhotos] = useState({
    before: [],
    after: []
  });
  const [selectedPhoto, setSelectedPhoto] = useState(null);
  const [viewerOpen, setViewerOpen] = useState(false);
  const [compareMode, setCompareMode] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [converting, setConverting] = useState(false);
  const [metadata, setMetadata] = useState({
    zone: '',
    angle: 'front',
    lighting: 'natural',
    flash: false
  });

  const webcamRef = useRef(null);
  const [cameraOpen, setCameraOpen] = useState(false);
  const [cameraType, setCameraType] = useState('before');

  // Поддерживаемые форматы
  const acceptedFormats = {
    'image/jpeg': ['.jpg', '.jpeg'],
    'image/png': ['.png'],
    'image/heic': ['.heic'],
    'image/heif': ['.heif'],
    'image/webp': ['.webp']
  };

  // Конвертация HEIC в JPEG
  const convertHEICtoJPEG = async (file) => {
    setConverting(true);
    try {
      const blob = await heic2any({
        blob: file,
        toType: 'image/jpeg',
        quality: 0.9
      });

      // Создаем новый File объект
      const convertedFile = new File(
        [blob],
        file.name.replace(/\.heic$/i, '.jpg'),
        { type: 'image/jpeg' }
      );

      setConverting(false);
      return convertedFile;
    } catch (error) {
      logger.error('Ошибка конвертации HEIC:', error);
      setConverting(false);
      throw error;
    }
  };

  // Обработка загрузки файлов
  const handleFileDrop = useCallback(async (acceptedFiles, fileType) => {
    for (const file of acceptedFiles) {
      setUploadProgress(0);

      try {
        // Проверяем и конвертируем HEIC
        let processedFile = file;
        if (file.type === 'image/heic' || file.name.toLowerCase().endsWith('.heic')) {
          processedFile = await convertHEICtoJPEG(file);
        }

        // Создаем превью
        const reader = new FileReader();
        reader.onload = async (e) => {
          const preview = e.target.result;

          // Загружаем на сервер
          const formData = new FormData();
          formData.append('file', processedFile);
          formData.append('kind', fileType === 'before' ? 'photo_before' : 'photo_after');
          formData.append('visit_id', visitId);
          formData.append('metadata', JSON.stringify(metadata));

          const response = await api.post(`/visits/${visitId}/files`, formData, {
            headers: { 'Content-Type': 'multipart/form-data' },
            onUploadProgress: (progressEvent) => {
              const percentCompleted = Math.round(
                progressEvent.loaded * 100 / progressEvent.total
              );
              setUploadProgress(percentCompleted);
            }
          });

          const newPhoto = {
            id: response.data.id,
            url: response.data.url,
            preview: preview,
            name: processedFile.name,
            size: processedFile.size,
            uploadedAt: new Date().toISOString(),
            metadata: metadata
          };

          setPhotos((prev) => ({
            ...prev,
            [fileType]: [...prev[fileType], newPhoto]
          }));

          setUploadProgress(0);
