        headers: { 'Authorization': `Bearer ${tokenManager.getAccessToken()}` }
      });

      if (response.ok) {
        const data = await response.json();
        setQueueData(data);
      } else {
        const error = await response.json();
        setMessage({ type: 'error', text: error.detail });
      }
